scwin.f_Print = async function () {
  var ozMode = "";
  var argDs = ds_transCost;
  if (tac_tabControl1.getSelectedTabID() == "tabs1") {
    argDs = ds_transCost;
    if (chb_printCheckPre_transCost.getValue() != true) {
      // 미리보기만 체크된 경우
      ozMode = "export";
    } else {
      ozMode = "silent";
    }
  } else if (tac_tabControl1.getSelectedTabID() == "tabs2") {
    argDs = ds_storageCharge;
    if (chb_printCheckPre_storageCharge.getValue() != true) {
      // 미리보기만 체크된 경우
      ozMode = "export";
    } else {
      ozMode = "silent";
    }
  }
  if (argDs.getRowCount() > 0) {
    var data = {
      // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
      reportName: "ds/op/wrkrslts/transwrkrslts/op_304_01_68p.ozr",
      odiParam: {
        CLOSE_YM: ed_closeYm.getValue()
      },
      viewerParam: {
        useprogressbar: false,
        // 프로그레스바 쓸지 말지
        zoom: 100,
        // 배율 설정
        mode: ozMode
      },
      formParam: {}
    };
    let opts = {
      id: "ozReportPopup",
      popupName: "오즈 리포트",
      modal: true,
      type: "browserPopup",
      width: 1000,
      height: 600,
      title: "오즈 리포트"
    };
    await $c.win.openPopup($p, "/ui/cm/zz/ozreportPopup.xml", opts, data);
  }
};
